package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;
import java.lang.reflect.Field;

public class CSVFormatTest {

    @Test
    public void testIsQuoteCharacterSet() throws Exception {
        // Given
        CSVFormat csvFormat = CSVFormat.DEFAULT;

        // When
        boolean result = csvFormat.isQuoteCharacterSet();

        // Then
        assertFalse(result);
    }

    @Test
    public void testIsQuoteCharacterSetWithQuoteCharacter() throws Exception {
        // Given
        CSVFormat csvFormat = CSVFormat.DEFAULT;
        // Set quoteCharacter using reflection
        Field field = CSVFormat.class.getDeclaredField("quoteCharacter");
        field.setAccessible(true);
        field.set(csvFormat, '\'');

        // When
        boolean result = csvFormat.isQuoteCharacterSet();

        // Then
        assertTrue(result);
    }
}
